CREATE OR REPLACE FUNCTION public.set_created_by_grupos_tareas_fn()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
begin
  new.created_by := auth.uid();
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.set_created_by_grupos_fn()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
begin
  new.created_by := auth.uid();
  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.crear_grupo_gastos(p_nombre text)
 RETURNS grupos
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_grupo grupos;
  v_user_id uuid := auth.uid();
begin
  if v_user_id is null then raise exception 'No autenticado'; end if;
  insert into grupos (nombre, tipo) values (p_nombre, 'gastos') returning * into v_grupo;
  return v_grupo;
end;
$function$

CREATE OR REPLACE FUNCTION public.crear_grupo_tareas(p_nombre text)
 RETURNS grupos
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_grupo grupos;
  v_user_id uuid := auth.uid();
begin
  if v_user_id is null then raise exception 'No autenticado'; end if;
  insert into grupos (nombre, tipo) values (p_nombre, 'tareas') returning * into v_grupo;
  return v_grupo;
end;
$function$
